Os percusos são implementados recursivamente da seguinte forma:
void pre_order(Node *root) {
    if (root != NULL) {
        printf("%d ", root-&gt;key);
        pre_order(root-&gt;left);
        pre_order(root-&gt;right);
    }
}

void in_order(Node *root) {
    if (root != NULL) {
        in_order(root-&gt;left);
        printf("%d ", root-&gt;key);
        in_order(root-&gt;right);
    }
}

void pos_order(Node *root) {
    if (root != NULL) {
        pos_order(root-&gt;left);
        pos_order(root-&gt;right);
        printf("%d ", root-&gt;key);
    }
}
