  add_edge(mat, 0, 1, 1); // Liga 'a' e 'b' 
  add_edge(mat, 0, 2, 1); // Liga 'a' e 'c'
  add_edge(mat, 1, 2, 1); // Liga 'b' e 'c'
  add_edge(mat, 1, 3, 1); // Liga 'b' e 'd'

  printf("Representação por Matriz de Adjacencia:\n");
