  size_t v = 2;
  size_t* neighbor = malloc(V * sizeof(size_t));
  size_t deg = neighborhood(g, v, neighbor);

  printf("\nO vertice v = %zu possui %zu vizinho(s): ", v, deg);

  display_neighborhood(neighbor, deg);

  destroy_graph(g);
  free(neighbor); 

